import { decode } from './contract/decode.js';
import { LoginResponseSchema } from './contract/schemas.js';
import { HttpClient, type HttpClientOptions } from './http.js';
import { ResourceCache } from './cache/ResourceCache.js';
import type { QueryKey, QueryOptions, ResourceState } from './cache/types.js';
import { AccountResource } from './resources/account.js';
import { AuthResource, type UserLoginInfo } from './resources/auth.js';
import { EnvResource } from './resources/env.js';
import { LookupResource } from './resources/lookup.js';
import { ProjectsResource } from './resources/projects.js';
import { InvitesResource } from './resources/invites.js';
import { SessionStore } from './session/SessionStore.js';
import type { SessionEvent } from './session/types.js';
import type { Subscribable } from './reactive/subscribable.js';
import type { LoginResponse } from './types.js';

export interface ToughLeafClientOptions extends HttpClientOptions {
  onLogin?: (session: LoginResponse) => void | Promise<void>;
}

/**
 * Framework-agnostic Tough Leaf API client (/api/v1).
 */
export class ToughLeafClient {
  readonly http: HttpClient;
  readonly session: SessionStore;
  readonly auth: AuthResource;
  readonly env: EnvResource;
  readonly lookup: LookupResource;
  readonly account: AccountResource;
  readonly invites: InvitesResource;
  readonly projects: ProjectsResource;

  private readonly cache: ResourceCache;
  private accessToken?: string;
  private readonly externalGetAccessToken?: HttpClientOptions['getAccessToken'];
  private readonly onLogin?: (session: LoginResponse) => void | Promise<void>;

  constructor(options: ToughLeafClientOptions) {
    this.onLogin = options.onLogin;
    this.externalGetAccessToken = options.getAccessToken;

    this.http = new HttpClient({
      baseUrl: options.baseUrl,
      fetchImpl: options.fetchImpl,
      getAccessToken: async () => this.resolveAccessToken(),
      onUnauthorized: async () => {
        await options.onUnauthorized?.();
        this.clearSession('SIGNED_OUT');
      },
    });

    this.session = new SessionStore();
    this.cache = new ResourceCache(this.http.transport);
    this.auth = new AuthResource(this.http);
    this.env = new EnvResource(this.http);
    this.lookup = new LookupResource(this.http);
    this.account = new AccountResource(this.http, this.cache);
    this.invites = new InvitesResource(this.http, this.cache);
    this.projects = new ProjectsResource(this.http, this.cache);
  }

  /** @deprecated Use createClient() — alias kept for v0.2 consumers */
  static create(options: ToughLeafClientOptions): ToughLeafClient {
    return new ToughLeafClient(options);
  }

  setAccessToken(token: string | undefined): void {
    this.accessToken = token;
  }

  getAccessToken(): string | undefined {
    return this.accessToken;
  }

  resource<T>(
    key: QueryKey,
    queryFn: (signal: AbortSignal) => Promise<T>,
    options?: QueryOptions,
  ): Subscribable<ResourceState<T>> {
    return this.cache.observeQuery(key, queryFn, options);
  }

  invalidate(keys: QueryKey | QueryKey[]): void {
    this.cache.invalidate(keys);
  }

  async login(info: UserLoginInfo): Promise<LoginResponse> {
    return this.applySession(await this.auth.login(info), 'SIGNED_IN');
  }

  async refresh(): Promise<LoginResponse> {
    return this.applySession(await this.auth.refresh(), 'TOKEN_REFRESHED');
  }

  logout(): void {
    this.clearSession('SIGNED_OUT');
  }

  private async resolveAccessToken(): Promise<string | undefined> {
    if (this.accessToken) {
      return this.accessToken;
    }
    return this.externalGetAccessToken ? await this.externalGetAccessToken() : undefined;
  }

  private async applySession(raw: LoginResponse, event: SessionEvent): Promise<LoginResponse> {
    const session = decode(LoginResponseSchema, raw, 'login');
    this.setAccessToken(session.access_token);
    this.session.setSession(
      {
        access_token: session.access_token,
        user: {
          id: session.id,
          email: session.email,
          first_name: session.first_name,
          last_name: session.last_name,
          status: session.status,
          company_id: session.company_id,
        },
        event,
      },
      event,
    );
    if (this.onLogin) {
      await this.onLogin(session);
    }
    return session;
  }

  private clearSession(event: SessionEvent): void {
    this.setAccessToken(undefined);
    this.session.setSession(null, event);
    this.cache.onAuthChange(false);
    this.http.abortAuthenticated('session ended');
  }
}

/** Preferred entry point for new consumers (v0.3+). */
export function createClient(options: ToughLeafClientOptions): ToughLeafClient {
  return new ToughLeafClient(options);
}
