export type QueryKey = readonly unknown[];

export type ResourceStatus = 'idle' | 'loading' | 'success' | 'error';

export interface ResourceState<T> {
  readonly status: ResourceStatus;
  readonly data?: T;
  readonly error?: Error;
  readonly isLoading: boolean;
  readonly isFetching: boolean;
  readonly isStale: boolean;
  readonly updatedAt: number;
}

export interface QueryOptions {
  staleTime?: number;
  gcTime?: number;
  signal?: AbortSignal;
}

export const USER_ME_KEY = ['user', 'me'] as const;
export const COMPANY_ME_KEY = ['company', 'me'] as const;
export const NOTIFICATION_PREFS_KEY = ['company', 'notification-preferences'] as const;
export const COMPANY_PREFIX_KEY = ['company'] as const;
export const INVITES_KEY = ['invites', 'list'] as const;
export const COMPANY_PEOPLE_KEY = ['company', 'people'] as const;

export const PROJECTS_LIST_KEY = ['projects', 'list'] as const;
export const PROJECTS_PREFIX_KEY = ['projects'] as const;

export function projectsListKey(params?: Record<string, unknown>): QueryKey {
  if (!params) {
    return PROJECTS_LIST_KEY;
  }
  const normalized = Object.entries(params)
    .filter(([, value]) => value !== undefined && value !== null)
    .sort(([a], [b]) => a.localeCompare(b));
  return normalized.length ? ['projects', 'list', Object.fromEntries(normalized)] : PROJECTS_LIST_KEY;
}

export function projectKey(projectId: string | number): QueryKey {
  return ['projects', projectId];
}

export function projectFullKey(projectId: string | number): QueryKey {
  return ['projects', projectId, { full: true }];
}

export function participantsKey(projectId: string | number): QueryKey {
  return ['projects', projectId, 'participants'];
}

export function bidPackageKey(
  projectId: string | number,
  packageId: string | number,
): QueryKey {
  return ['projects', projectId, 'bid_package', packageId];
}

export function serializeQueryKey(key: QueryKey): string {
  return JSON.stringify(key);
}

export function queryKeyMatchesPrefix(key: QueryKey, prefix: QueryKey): boolean {
  if (prefix.length > key.length) {
    return false;
  }
  return prefix.every((part, index) => key[index] === part);
}

/** Auth-scoped cache prefixes cleared on logout */
export const AUTH_CACHE_PREFIXES: QueryKey[] = [
  ['user'],
  ['company'],
  ['projects'],
  ['invites'],
];

export function isAuthScopedKey(key: QueryKey): boolean {
  return AUTH_CACHE_PREFIXES.some((prefix) => queryKeyMatchesPrefix(key, prefix));
}
