import type { Static, TSchema } from '@sinclair/typebox';
import { Errors } from '@sinclair/typebox/errors';
import { Check, Clean } from '@sinclair/typebox/value';

export class ValidationError extends Error {
  readonly issues: unknown;

  constructor(message: string, issues: unknown) {
    super(message);
    this.name = 'ValidationError';
    this.issues = issues;
  }
}

export function decode<T extends TSchema>(schema: T, raw: unknown, label: string): Static<T> {
  if (!Check(schema, raw)) {
    throw new ValidationError(`Invalid ${label} response`, [...Errors(schema, raw)]);
  }
  return Clean(schema, raw) as Static<T>;
}
