import { decode } from '../contract/decode.js';
import type { ResourceCache } from '../cache/ResourceCache.js';
import {
  PROJECTS_PREFIX_KEY,
  bidPackageKey,
  participantsKey,
  projectFullKey,
  projectKey,
  projectsListKey,
  type QueryKey,
  type QueryOptions,
} from '../cache/types.js';
import type { HttpClient } from '../http.js';
import type { TSchema } from '@sinclair/typebox';
import { Type } from '@sinclair/typebox';
import type { HttpMethod } from '../transport/types.js';
import type {
  BidPackageBatchPayload,
  BidPackageData,
  BidPackagePayload,
  ProjectBatchPayload,
  ProjectContactPayload,
  ProjectData,
  ProjectParticipant,
  ProjectParticipantsPayload,
  ProjectPayload,
  QueryParams,
} from '../types.js';

const ProjectDataSchema = Type.Object(
  { id: Type.Number(), name: Type.Optional(Type.String()), slug: Type.Optional(Type.String()) },
  { additionalProperties: true },
);

const ProjectListSchema = Type.Array(ProjectDataSchema);

const ParticipantListSchema = Type.Array(
  Type.Object({ id: Type.Optional(Type.Number()), user_id: Type.Optional(Type.Number()) }, {
    additionalProperties: true,
  }),
);

const BidPackageSchema = Type.Object(
  { id: Type.Number(), name: Type.Optional(Type.String()) },
  { additionalProperties: true },
);

export class ProjectsResource {
  constructor(
    private readonly http: HttpClient,
    private readonly cache?: ResourceCache,
  ) {}

  async list(params?: QueryParams, options?: QueryOptions): Promise<ProjectData[]> {
    if (this.cache) {
      return this.cache.fetchQuery(
        projectsListKey(params),
        (signal) => this.fetchList(params, signal),
        options,
      );
    }
    return (await this.http.get<ProjectData[]>('/projects', params)).data;
  }

  async get(
    projectId: string | number,
    options?: { full?: boolean } & QueryOptions,
  ): Promise<ProjectData> {
    const { full, ...queryOptions } = options ?? {};
    const params = full ? { full: true } : undefined;
    const key = full ? projectFullKey(projectId) : projectKey(projectId);

    if (this.cache) {
      return this.cache.fetchQuery(
        key,
        (signal) => this.fetchOne(projectId, params, signal),
        queryOptions,
      );
    }
    return (await this.http.get<ProjectData>(`/projects/${projectId}`, params)).data;
  }

  async createOrUpdate(
    payload: ProjectPayload,
    projectId?: string | number,
  ): Promise<ProjectData> {
    if (projectId !== undefined) {
      return this.mutateAndInvalidate(
        { method: 'PUT', path: `/projects/${projectId}`, body: payload },
        ProjectDataSchema,
        'project',
        [PROJECTS_PREFIX_KEY, projectKey(projectId)],
      );
    }
    return this.mutateAndInvalidate(
      { method: 'POST', path: '/projects', body: payload },
      ProjectDataSchema,
      'project',
      [PROJECTS_PREFIX_KEY],
    );
  }

  async delete(projectId: string | number): Promise<void> {
    await this.http.transport.request<unknown>({
      method: 'DELETE',
      path: `/projects/${projectId}`,
      authRequired: true,
    });
    this.invalidateProject(projectId);
  }

  async batch(payload: ProjectBatchPayload): Promise<unknown> {
    const result = await this.http.transport.request<unknown>({
      method: 'POST',
      path: '/projects/batch',
      body: payload,
      authRequired: true,
    });
    this.cache?.invalidate(PROJECTS_PREFIX_KEY);
    return result;
  }

  async addOrUpdateContact(
    projectId: string | number,
    payload: ProjectContactPayload,
    contactId?: string | number,
  ): Promise<unknown> {
    const path =
      contactId !== undefined
        ? `/projects/${projectId}/contacts/${contactId}`
        : `/projects/${projectId}/contacts`;
    const method = contactId !== undefined ? 'PUT' : 'POST';
    const result = await this.http.transport.request<unknown>({
      method,
      path,
      body: payload,
      authRequired: true,
    });
    this.cache?.invalidate(projectKey(projectId));
    return result;
  }

  async deleteContact(projectId: string | number, contactId: string | number): Promise<void> {
    await this.http.transport.request<unknown>({
      method: 'DELETE',
      path: `/projects/${projectId}/contacts/${contactId}`,
      authRequired: true,
    });
    this.cache?.invalidate(projectKey(projectId));
  }

  async listParticipants(
    projectId: string | number,
    options?: QueryOptions,
  ): Promise<ProjectParticipant[]> {
    const key = participantsKey(projectId);
    if (this.cache) {
      return this.cache.fetchQuery(
        key,
        (signal) => this.fetchParticipants(projectId, signal),
        options,
      );
    }
    return (await this.http.get<ProjectParticipant[]>(`/projects/${projectId}/participants`)).data;
  }

  async addParticipants(
    projectId: string | number,
    payload: ProjectParticipantsPayload,
  ): Promise<unknown> {
    const result = await this.http.transport.request<unknown>({
      method: 'POST',
      path: `/projects/${projectId}/participants/add`,
      body: payload,
      authRequired: true,
    });
    this.invalidateParticipants(projectId);
    return result;
  }

  async removeParticipants(
    projectId: string | number,
    payload: ProjectParticipantsPayload,
  ): Promise<unknown> {
    const result = await this.http.transport.request<unknown>({
      method: 'POST',
      path: `/projects/${projectId}/participants/remove`,
      body: payload,
      authRequired: true,
    });
    this.invalidateParticipants(projectId);
    return result;
  }

  async getBidPackage(
    projectId: string | number,
    packageId: string | number,
    options?: QueryOptions,
  ): Promise<BidPackageData> {
    const key = bidPackageKey(projectId, packageId);
    if (this.cache) {
      return this.cache.fetchQuery(
        key,
        (signal) => this.fetchBidPackage(projectId, packageId, signal),
        options,
      );
    }
    return (
      await this.http.get<BidPackageData>(`/projects/${projectId}/bid_packages/${packageId}`)
    ).data;
  }

  async createOrUpdateBidPackage(
    projectId: string | number,
    payload: BidPackagePayload,
    packageId?: string | number,
  ): Promise<BidPackageData> {
    const path =
      packageId !== undefined
        ? `/projects/${projectId}/bid_packages/${packageId}`
        : `/projects/${projectId}/bid_packages`;
    const method = packageId !== undefined ? 'PUT' : 'POST';
    const raw = await this.http.transport.request<unknown>({
      method,
      path,
      body: payload,
      authRequired: true,
    });
    const data = decode(BidPackageSchema, raw, 'bid-package') as BidPackageData;
    this.invalidateBidPackage(projectId, packageId ?? data.id);
    return data;
  }

  async deleteBidPackage(projectId: string | number, packageId: string | number): Promise<void> {
    await this.http.transport.request<unknown>({
      method: 'DELETE',
      path: `/projects/${projectId}/bid_packages/${packageId}`,
      authRequired: true,
    });
    this.invalidateBidPackage(projectId, packageId);
  }

  async batchBidPackages(
    projectId: string | number,
    payload: BidPackageBatchPayload,
  ): Promise<unknown> {
    const result = await this.http.transport.request<unknown>({
      method: 'POST',
      path: `/projects/${projectId}/bid-packages/batch`,
      body: payload,
      authRequired: true,
    });
    this.cache?.invalidate(projectKey(projectId));
    this.cache?.invalidate(PROJECTS_PREFIX_KEY);
    return result;
  }

  private async fetchList(params: QueryParams | undefined, signal: AbortSignal): Promise<ProjectData[]> {
    const raw = await this.http.transport.request<ProjectData[]>({
      method: 'GET',
      path: '/projects',
      params,
      authRequired: true,
      signal,
    });
    return decode(ProjectListSchema, raw, 'projects');
  }

  private async fetchOne(
    projectId: string | number,
    params: QueryParams | undefined,
    signal: AbortSignal,
  ): Promise<ProjectData> {
    const raw = await this.http.transport.request<ProjectData>({
      method: 'GET',
      path: `/projects/${projectId}`,
      params,
      authRequired: true,
      signal,
    });
    return decode(ProjectDataSchema, raw, 'project');
  }

  private async fetchParticipants(
    projectId: string | number,
    signal: AbortSignal,
  ): Promise<ProjectParticipant[]> {
    const raw = await this.http.transport.request<ProjectParticipant[]>({
      method: 'GET',
      path: `/projects/${projectId}/participants`,
      authRequired: true,
      signal,
    });
    return decode(ParticipantListSchema, raw, 'participants');
  }

  private async fetchBidPackage(
    projectId: string | number,
    packageId: string | number,
    signal: AbortSignal,
  ): Promise<BidPackageData> {
    const raw = await this.http.transport.request<BidPackageData>({
      method: 'GET',
      path: `/projects/${projectId}/bid_packages/${packageId}`,
      authRequired: true,
      signal,
    });
    return decode(BidPackageSchema, raw, 'bid-package');
  }

  private async mutateAndInvalidate<T>(
    spec: { method: HttpMethod; path: string; body?: unknown },
    schema: TSchema,
    label: string,
    invalidateKeys: QueryKey[],
  ): Promise<T> {
    const raw = await this.http.transport.request<unknown>({
      ...spec,
      authRequired: true,
    });
    const data = decode(schema, raw, label) as T;
    if (this.cache) {
      for (const key of invalidateKeys) {
        this.cache.invalidate(key);
      }
    }
    return data;
  }

  private invalidateProject(projectId: string | number): void {
    this.cache?.invalidate(PROJECTS_PREFIX_KEY);
    this.cache?.invalidate(projectKey(projectId));
    this.cache?.invalidate(projectFullKey(projectId));
  }

  private invalidateParticipants(projectId: string | number): void {
    this.cache?.invalidate(participantsKey(projectId));
    this.cache?.invalidate(projectKey(projectId));
    this.cache?.invalidate(projectFullKey(projectId));
  }

  private invalidateBidPackage(projectId: string | number, packageId: string | number): void {
    this.cache?.invalidate(bidPackageKey(projectId, packageId));
    this.cache?.invalidate(projectKey(projectId));
    this.cache?.invalidate(projectFullKey(projectId));
    this.cache?.invalidate(PROJECTS_PREFIX_KEY);
  }
}
