import { decode } from '../contract/decode.js';
import type { ResourceCache } from '../cache/ResourceCache.js';
import { INVITES_KEY, type QueryKey, type QueryOptions } from '../cache/types.js';
import type { HttpClient } from '../http.js';
import type { TSchema } from '@sinclair/typebox';
import { Type } from '@sinclair/typebox';
import type { HttpMethod } from '../transport/types.js';
import type { AcceptInvitePayload, CreateInvitePayload, InviteData } from '../types.js';

const InviteDataSchema = Type.Object(
  {
    id: Type.Number(),
    email: Type.Optional(Type.String()),
    status: Type.Optional(Type.String()),
  },
  { additionalProperties: true },
);

const InviteListSchema = Type.Array(InviteDataSchema);

export class InvitesResource {
  constructor(
    private readonly http: HttpClient,
    private readonly cache?: ResourceCache,
  ) {}

  async list(options?: QueryOptions): Promise<InviteData[]> {
    if (this.cache) {
      return this.cache.fetchQuery(INVITES_KEY, (signal) => this.fetchList(signal), options);
    }
    return (await this.http.get<InviteData[]>('/invites')).data;
  }

  async get(inviteId: string | number): Promise<InviteData> {
    const raw = await this.http.transport.request<InviteData>({
      method: 'GET',
      path: `/invites/${inviteId}`,
      authRequired: true,
    });
    return decode(InviteDataSchema, raw, 'invite');
  }

  async create(payload: CreateInvitePayload): Promise<InviteData> {
    return this.mutateAndInvalidate(
      { method: 'POST', path: '/invites', body: payload },
      InviteDataSchema,
      'invite',
      INVITES_KEY,
    );
  }

  async resend(inviteId: string | number): Promise<InviteData> {
    return this.mutateAndInvalidate(
      { method: 'PUT', path: `/invites/${inviteId}`, body: {} },
      InviteDataSchema,
      'invite',
      INVITES_KEY,
    );
  }

  async delete(inviteId: string | number): Promise<void> {
    await this.http.transport.request<unknown>({
      method: 'DELETE',
      path: `/invites/${inviteId}`,
      authRequired: true,
    });
    this.cache?.invalidate(INVITES_KEY);
  }

  async accept(token: string, payload: AcceptInvitePayload): Promise<unknown> {
    return this.http.transport.request<unknown>({
      method: 'POST',
      path: `/invites/${token}/accept`,
      body: payload,
      authRequired: false,
    });
  }

  private async fetchList(signal: AbortSignal): Promise<InviteData[]> {
    const raw = await this.http.transport.request<InviteData[]>({
      method: 'GET',
      path: '/invites',
      authRequired: true,
      signal,
    });
    return decode(InviteListSchema, raw, 'invites');
  }

  private async mutateAndInvalidate<T>(
    spec: { method: HttpMethod; path: string; body?: unknown },
    schema: TSchema,
    label: string,
    invalidateKey?: QueryKey,
  ): Promise<T> {
    const raw = await this.http.transport.request<unknown>({
      ...spec,
      authRequired: true,
    });
    const data = decode(schema, raw, label) as T;
    if (invalidateKey && this.cache) {
      this.cache.invalidate(invalidateKey);
    }
    return data;
  }
}
