import type { HttpClient } from '../http.js';
import type { EnvFeatures } from '../types.js';

export class EnvResource {
  constructor(private readonly http: HttpClient) {}

  async getConfig(): Promise<Record<string, unknown>> {
    const resp = await this.http.get<Record<string, unknown>>('/env/config');
    return resp.data;
  }

  async getFeatures(): Promise<EnvFeatures> {
    const resp = await this.http.get<EnvFeatures>('/env/features');
    return resp.data;
  }
}
