import { Type, type Static, type TSchema } from '@sinclair/typebox';

export const ApiEnvelopeSchema = <T extends TSchema>(dataSchema: T) =>
  Type.Object({
    success: Type.Literal(true),
    data: dataSchema,
  });

export const UserDataSchema = Type.Object(
  {
    id: Type.Number(),
    email: Type.String(),
    first_name: Type.String(),
    last_name: Type.String(),
    status: Type.Optional(Type.Number()),
    company_id: Type.Optional(Type.Number()),
  },
  { additionalProperties: true },
);

export const LoginResponseSchema = Type.Object({
  access_token: Type.String(),
  token_type: Type.Literal('Bearer'),
  id: Type.Number(),
  email: Type.String(),
  first_name: Type.String(),
  last_name: Type.String(),
  status: Type.Number(),
  company_id: Type.Number(),
  company_type: Type.Number(),
});

export const CompanyDataSchema = Type.Object(
  {
    id: Type.Number(),
    company_name: Type.Optional(Type.String()),
    company_type: Type.Optional(Type.Number()),
  },
  { additionalProperties: true },
);

export const NotificationPreferencesSchema = Type.Record(Type.String(), Type.Unknown());

export type UserDataValidated = Static<typeof UserDataSchema>;
export type LoginResponseValidated = Static<typeof LoginResponseSchema>;
export type CompanyDataValidated = Static<typeof CompanyDataSchema>;
export type NotificationPreferencesValidated = Static<typeof NotificationPreferencesSchema>;
