import type { HttpClient } from '../http.js';
import type { QueryParams, StateLookup } from '../types.js';

export class LookupResource {
  constructor(private readonly http: HttpClient) {}

  async listStates(): Promise<StateLookup[]> {
    return (await this.http.get<StateLookup[]>('/lookup/states')).data;
  }

  async listCapabilities(query?: QueryParams): Promise<{ id: number; name: string }[]> {
    return (await this.http.get<{ id: number; name: string }[]>('/lookup/capabilities', query)).data;
  }

  async listCertifications(query?: QueryParams): Promise<unknown[]> {
    return (await this.http.get<unknown[]>('/lookup/certifications', query)).data;
  }

  async listCertificationTree(): Promise<Record<string, unknown>> {
    return (await this.http.get<Record<string, unknown>>('/lookup/certification_tree')).data;
  }

  async listEthnicities(): Promise<string[]> {
    return (await this.http.get<string[]>('/lookup/ethnicities')).data;
  }

  async listUnions(query?: QueryParams): Promise<unknown[]> {
    return (await this.http.get<unknown[]>('/lookup/unions', query)).data;
  }

  async listCommodityCodes(query?: QueryParams): Promise<unknown[]> {
    return (await this.http.get<unknown[]>('/lookup/commodity_codes', query)).data;
  }

  async listBusinessSizes(): Promise<{ id: number; text: string; code: string }[]> {
    return (await this.http.get<{ id: number; text: string; code: string }[]>('/lookup/business_sizes')).data;
  }

  async listCategories(): Promise<unknown[]> {
    return (await this.http.get<unknown[]>('/lookup/categories')).data;
  }
}
