import { BehaviorSubject, type Observable } from 'rxjs';
import type { Session, SessionEvent } from './types.js';

function freezeSession(session: Session): Session {
  return Object.freeze({ ...session });
}

export class SessionStore {
  private readonly subject = new BehaviorSubject<Session | null>(null);
  private lastEvent?: SessionEvent;

  readonly state$: Observable<Session | null> = this.subject.asObservable();

  getSession(): Session | null {
    return this.subject.getValue();
  }

  setSession(session: Session | null, event?: SessionEvent): void {
    if (event) {
      this.lastEvent = event;
    }
    const next =
      session === null
        ? null
        : freezeSession({ ...session, event: event ?? session.event });
    this.subject.next(next);
  }

  subscribe(callback: (session: Session | null, event?: SessionEvent) => void): {
    unsubscribe: () => void;
  } {
    const sub = this.state$.subscribe((session) => {
      callback(session, session?.event ?? (session === null ? this.lastEvent : undefined));
    });
    return { unsubscribe: () => sub.unsubscribe() };
  }
}
