import { decode } from '../contract/decode.js';
import {
  CompanyDataSchema,
  NotificationPreferencesSchema,
  UserDataSchema,
} from '../contract/schemas.js';
import type { ResourceCache } from '../cache/ResourceCache.js';
import {
  COMPANY_ME_KEY,
  COMPANY_PEOPLE_KEY,
  COMPANY_PREFIX_KEY,
  NOTIFICATION_PREFS_KEY,
  USER_ME_KEY,
  type QueryKey,
  type QueryOptions,
  type ResourceState,
} from '../cache/types.js';
import type { HttpClient } from '../http.js';
import type { Subscribable } from '../reactive/subscribable.js';
import type { TSchema } from '@sinclair/typebox';
import { Type } from '@sinclair/typebox';
import type { HttpMethod } from '../transport/types.js';
import type {
  CompanyData,
  NotificationPreferences,
  UpdateCompanyUserPayload,
  UpdatePasswordPayload,
  UpdateUserPayload,
  UserData,
} from '../types.js';
import { buildLaravelAccountCompanyPutBody } from './laravel-account-company.js';

const CompanyPeopleSchema = Type.Array(UserDataSchema);

export class AccountResource {
  constructor(
    private readonly http: HttpClient,
    private readonly cache?: ResourceCache,
  ) {}

  async getUser(options?: QueryOptions): Promise<UserData> {
    if (this.cache) {
      return this.cache.fetchQuery(USER_ME_KEY, (signal) => this.fetchUser(signal), options);
    }
    return (await this.http.get<UserData>('/user')).data;
  }

  observeUser(options?: QueryOptions): Subscribable<ResourceState<UserData>> {
    if (!this.cache) {
      throw new Error('observeUser requires a cache-enabled client');
    }
    return this.cache.observeQuery(USER_ME_KEY, (signal) => this.fetchUser(signal), options);
  }

  async updateUser(payload: UpdateUserPayload): Promise<UserData> {
    return this.mutateAndInvalidate(
      { method: 'PUT', path: '/user', body: payload },
      UserDataSchema,
      'user',
      USER_ME_KEY,
      () => this.getUser(),
    );
  }

  async updatePassword(payload: UpdatePasswordPayload): Promise<void> {
    await this.http.transport.request<unknown>({
      method: 'PUT',
      path: '/user/password',
      body: payload,
      authRequired: true,
    });
  }

  async getCompany(options?: QueryOptions): Promise<CompanyData> {
    if (this.cache) {
      return this.cache.fetchQuery(
        COMPANY_ME_KEY,
        (signal) => this.fetchCompany(signal),
        options,
      );
    }
    return (await this.http.get<CompanyData>('/company')).data;
  }

  observeCompany(options?: QueryOptions): Subscribable<ResourceState<CompanyData>> {
    if (!this.cache) {
      throw new Error('observeCompany requires a cache-enabled client');
    }
    return this.cache.observeQuery(
      COMPANY_ME_KEY,
      (signal) => this.fetchCompany(signal),
      options,
    );
  }

  async createCompany(payload: Partial<CompanyData>): Promise<CompanyData> {
    return this.mutateAndInvalidate(
      { method: 'POST', path: '/company', body: payload },
      CompanyDataSchema,
      'company',
      COMPANY_PREFIX_KEY,
      () => this.getCompany(),
    );
  }

  async updateCompany(payload: Partial<CompanyData>): Promise<CompanyData> {
    const current = await this.fetchCompanyForMutate();
    const body = buildLaravelAccountCompanyPutBody(current, payload);
    return this.mutateAndInvalidate(
      { method: 'PUT', path: '/company', body },
      CompanyDataSchema,
      'company',
      COMPANY_PREFIX_KEY,
      () => this.getCompany(),
    );
  }

  async getNotificationPreferences(
    options?: QueryOptions,
  ): Promise<NotificationPreferences> {
    if (this.cache) {
      return this.cache.fetchQuery(
        NOTIFICATION_PREFS_KEY,
        (signal) => this.fetchNotificationPreferences(signal),
        options,
      );
    }
    return (await this.http.get<NotificationPreferences>('/company/notification-preferences'))
      .data;
  }

  async updateNotificationPreferences(
    payload: NotificationPreferences,
  ): Promise<NotificationPreferences> {
    return this.mutateAndInvalidate(
      { method: 'PUT', path: '/company/notification-preferences', body: payload },
      NotificationPreferencesSchema,
      'notification-preferences',
      NOTIFICATION_PREFS_KEY,
      () => this.getNotificationPreferences(),
    );
  }

  async listCompanyPeople(options?: QueryOptions): Promise<UserData[]> {
    if (this.cache) {
      return this.cache.fetchQuery(
        COMPANY_PEOPLE_KEY,
        (signal) => this.fetchCompanyPeople(signal),
        options,
      );
    }
    const raw = await this.http.transport.request<UserData[]>({
      method: 'GET',
      path: '/company/people',
      authRequired: true,
    });
    return decode(CompanyPeopleSchema, raw, 'company-people') as UserData[];
  }

  async updateCompanyUser(
    userId: string | number,
    payload: UpdateCompanyUserPayload,
  ): Promise<UserData> {
    return this.mutateAndInvalidate(
      { method: 'PUT', path: `/company/people/${userId}`, body: payload },
      UserDataSchema,
      'company-user',
      COMPANY_PEOPLE_KEY,
      async () => {
        const people = await this.listCompanyPeople();
        const match = people.find((u) => String(u.id) === String(userId));
        if (!match) {
          throw new Error(`Company user ${userId} not found after update`);
        }
        return match;
      },
    );
  }

  private async fetchUser(signal: AbortSignal): Promise<UserData> {
    const raw = await this.http.transport.request<UserData>({
      method: 'GET',
      path: '/user',
      authRequired: true,
      signal,
    });
    return decode(UserDataSchema, raw, 'user');
  }

  private async fetchCompanyForMutate(): Promise<CompanyData> {
    const raw = await this.http.transport.request<CompanyData>({
      method: 'GET',
      path: '/company',
      authRequired: true,
    });
    return raw as CompanyData;
  }

  private async fetchCompany(signal: AbortSignal): Promise<CompanyData> {
    const raw = await this.http.transport.request<CompanyData>({
      method: 'GET',
      path: '/company',
      authRequired: true,
      signal,
    });
    return decode(CompanyDataSchema, raw, 'company');
  }

  private async fetchNotificationPreferences(
    signal: AbortSignal,
  ): Promise<NotificationPreferences> {
    const raw = await this.http.transport.request<NotificationPreferences>({
      method: 'GET',
      path: '/company/notification-preferences',
      authRequired: true,
      signal,
    });
    return decode(NotificationPreferencesSchema, raw, 'notification-preferences');
  }

  private async fetchCompanyPeople(signal: AbortSignal): Promise<UserData[]> {
    const raw = await this.http.transport.request<UserData[]>({
      method: 'GET',
      path: '/company/people',
      authRequired: true,
      signal,
    });
    return decode(CompanyPeopleSchema, raw, 'company-people') as UserData[];
  }

  private async mutateAndInvalidate<T>(
    spec: { method: HttpMethod; path: string; body?: unknown },
    schema: TSchema,
    label: string,
    invalidateKey?: QueryKey,
    refetch?: () => Promise<T>,
  ): Promise<T> {
    const raw = await this.http.transport.request<unknown>({
      ...spec,
      authRequired: true,
    });

    const emptyBody = raw === undefined || raw === null;
    if (emptyBody) {
      if (invalidateKey && this.cache) {
        this.cache.invalidate(invalidateKey);
      }
      if (refetch) {
        return refetch();
      }
      throw new Error(`Empty ${label} response (expected Laravel 204 with refetch)`);
    }

    const data = decode(schema, raw, label) as T;
    if (invalidateKey && this.cache) {
      this.cache.invalidate(invalidateKey);
    }
    return data;
  }
}
