import { BehaviorSubject, type Subscription } from 'rxjs';
import type { HttpTransport } from '../transport/types.js';
import type { Subscribable, Subscription as TlSubscription } from '../reactive/subscribable.js';
import {
  isAuthScopedKey,
  queryKeyMatchesPrefix,
  serializeQueryKey,
  type QueryKey,
  type QueryOptions,
  type ResourceState,
} from './types.js';

type QueryFn<T> = (signal: AbortSignal) => Promise<T>;

interface QueryEntry<T = unknown> {
  state: ResourceState<T>;
  subject: BehaviorSubject<ResourceState<T>>;
  observerCount: number;
  controller?: AbortController;
  inFlight?: Promise<T>;
  queryFn?: QueryFn<T>;
  queryOptions?: QueryOptions;
  staleTime: number;
  gcTime: number;
  gcTimer?: ReturnType<typeof setTimeout>;
}

const DEFAULT_STALE_TIME = 0;
const DEFAULT_GC_TIME = 5 * 60 * 1000;

function initialState<T>(): ResourceState<T> {
  return {
    status: 'idle',
    isLoading: true,
    isFetching: false,
    isStale: false,
    updatedAt: 0,
  };
}

function freezeState<T>(state: ResourceState<T>): ResourceState<T> {
  const data =
    state.data === undefined
      ? undefined
      : Array.isArray(state.data)
        ? (Object.freeze([...state.data]) as T)
        : (Object.freeze({ ...(state.data as object) }) as T);
  const frozen: ResourceState<T> = Object.freeze({
    ...state,
    data,
  });
  return frozen;
}

export class ResourceCache {
  private readonly entries = new Map<string, QueryEntry>();
  private readonly transport: HttpTransport;

  constructor(transport: HttpTransport) {
    this.transport = transport;
  }

  async fetchQuery<T>(
    key: QueryKey,
    queryFn: QueryFn<T>,
    options: QueryOptions = {},
  ): Promise<T> {
    const entry = this.getOrCreateEntry<T>(key, options);
    entry.queryFn = queryFn;
    entry.queryOptions = options;
    const now = Date.now();
    const staleTime = options.staleTime ?? DEFAULT_STALE_TIME;

    if (
      entry.state.status === 'success' &&
      entry.state.data !== undefined &&
      now - entry.state.updatedAt < staleTime &&
      !entry.state.isStale
    ) {
      return entry.state.data;
    }

    if (entry.inFlight) {
      return entry.inFlight;
    }

    const externalSignal = options.signal;
    entry.inFlight = this.runFetch(entry, queryFn, externalSignal, false).finally(() => {
      entry.inFlight = undefined;
    });
    return entry.inFlight;
  }

  observeQuery<T>(
    key: QueryKey,
    queryFn: QueryFn<T>,
    options: QueryOptions = {},
  ): Subscribable<ResourceState<T>> {
    const entry = this.getOrCreateEntry<T>(key, options);
    entry.queryFn = queryFn;
    entry.queryOptions = options;

    return {
      subscribe: (observer: (value: ResourceState<T>) => void): TlSubscription => {
        entry.observerCount += 1;
        this.clearGcTimer(entry);

        const sub: Subscription = entry.subject.subscribe(observer);

        void this.ensureObserveFetch(entry, queryFn, options);

        return {
          unsubscribe: () => {
            sub.unsubscribe();
            entry.observerCount -= 1;
            if (entry.observerCount <= 0) {
              entry.observerCount = 0;
              if (entry.controller) {
                entry.controller.abort();
                entry.controller = undefined;
              }
              this.scheduleGc(key, entry);
            }
          },
        };
      },
    };
  }

  invalidate(keys: QueryKey | QueryKey[]): void {
    const list = Array.isArray(keys[0]) ? (keys as QueryKey[]) : [keys as QueryKey];
    for (const [serialized, entry] of this.entries) {
      const key = JSON.parse(serialized) as QueryKey;
      if (list.some((prefix) => queryKeyMatchesPrefix(key, prefix))) {
        entry.state = freezeState({
          ...entry.state,
          isStale: true,
        });
        entry.subject.next(entry.state);
        if (entry.controller) {
          entry.controller.abort();
          entry.controller = undefined;
        }
        if (entry.observerCount > 0 && entry.queryFn && !entry.inFlight) {
          entry.inFlight = this.runFetch(entry, entry.queryFn, undefined, true).finally(() => {
            entry.inFlight = undefined;
          });
        }
      }
    }
  }

  onAuthChange(authenticated: boolean): void {
    if (authenticated) {
      return;
    }
    this.transport.abortAuthenticated('session ended');
    for (const [serialized, entry] of this.entries) {
      const key = JSON.parse(serialized) as QueryKey;
      if (isAuthScopedKey(key)) {
        this.entries.delete(serialized);
        entry.subject.complete();
        if (entry.controller) {
          entry.controller.abort();
        }
      }
    }
  }

  private getOrCreateEntry<T>(key: QueryKey, options: QueryOptions): QueryEntry<T> {
    const serialized = serializeQueryKey(key);
    let entry = this.entries.get(serialized) as QueryEntry<T> | undefined;
    if (!entry) {
      const subject = new BehaviorSubject<ResourceState<T>>(initialState<T>());
      entry = {
        state: initialState<T>(),
        subject,
        observerCount: 0,
        staleTime: options.staleTime ?? DEFAULT_STALE_TIME,
        gcTime: options.gcTime ?? DEFAULT_GC_TIME,
      };
      this.entries.set(serialized, entry as QueryEntry);
    }
    return entry;
  }

  private async ensureObserveFetch<T>(
    entry: QueryEntry<T>,
    queryFn: QueryFn<T>,
    options: QueryOptions,
  ): Promise<void> {
    const now = Date.now();
    const staleTime = options.staleTime ?? entry.staleTime;

    if (
      entry.state.status === 'success' &&
      entry.state.data !== undefined &&
      now - entry.state.updatedAt < staleTime &&
      !entry.state.isStale
    ) {
      entry.subject.next(entry.state);
      return;
    }

    if (entry.inFlight && !entry.controller) {
      await entry.inFlight.catch(() => undefined);
      return;
    }

    if (entry.inFlight && entry.controller) {
      return;
    }

    entry.inFlight = this.runFetch(entry, queryFn, undefined, true).finally(() => {
      entry.inFlight = undefined;
    });
    await entry.inFlight.catch(() => undefined);
  }

  private async runFetch<T>(
    entry: QueryEntry<T>,
    queryFn: QueryFn<T>,
    externalSignal: AbortSignal | undefined,
    observeDriven: boolean,
  ): Promise<T> {
    const controller = new AbortController();
    if (observeDriven) {
      if (entry.controller) {
        entry.controller.abort();
      }
      entry.controller = controller;
    }

    if (externalSignal) {
      if (externalSignal.aborted) {
        controller.abort();
      } else {
        externalSignal.addEventListener('abort', () => controller.abort(), { once: true });
      }
    }

    this.setFetching(entry, true);

    try {
      const data = await queryFn(controller.signal);
      const next = freezeState<T>({
        status: 'success',
        data,
        isLoading: false,
        isFetching: false,
        isStale: false,
        updatedAt: Date.now(),
      });
      entry.state = next;
      entry.subject.next(next);
      return data;
    } catch (err) {
      if (controller.signal.aborted) {
        this.setFetching(entry, false);
        throw err;
      }
      const error = err instanceof Error ? err : new Error(String(err));
      const next = freezeState<T>({
        ...entry.state,
        status: 'error',
        error,
        isLoading: false,
        isFetching: false,
        isStale: false,
        updatedAt: Date.now(),
      });
      entry.state = next;
      entry.subject.next(next);
      throw error;
    } finally {
      if (observeDriven && entry.controller === controller) {
        entry.controller = undefined;
      }
    }
  }

  private setFetching<T>(entry: QueryEntry<T>, fetching: boolean): void {
    const isLoading = entry.state.status !== 'success' && fetching;
    const next = freezeState<T>({
      ...entry.state,
      isLoading,
      isFetching: fetching,
      status: entry.state.status === 'idle' && fetching ? 'loading' : entry.state.status,
    });
    entry.state = next;
    entry.subject.next(next);
  }

  private scheduleGc<T>(key: QueryKey, entry: QueryEntry<T>): void {
    this.clearGcTimer(entry);
    entry.gcTimer = setTimeout(() => {
      if (entry.observerCount === 0) {
        this.entries.delete(serializeQueryKey(key));
        entry.subject.complete();
      }
    }, entry.gcTime);
  }

  private clearGcTimer<T>(entry: QueryEntry<T>): void {
    if (entry.gcTimer) {
      clearTimeout(entry.gcTimer);
      entry.gcTimer = undefined;
    }
  }
}
