import { FetchTransport } from './transport/FetchTransport.js';
import type { FetchTransportOptions } from './transport/types.js';
import { parseApiError, ToughLeafApiError } from './errors.js';
import type { ApiResponse, QueryParams } from './types.js';

export type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE' | 'HEAD';

export type TokenProvider = () => string | undefined | Promise<string | undefined>;

export interface HttpClientOptions extends FetchTransportOptions {}

export class HttpClient {
  readonly transport: FetchTransport;

  constructor(options: HttpClientOptions) {
    this.transport = new FetchTransport(options);
  }

  get apiBaseUrl(): string {
    return this.transport.apiBaseUrl;
  }

  abortAuthenticated(reason?: string): void {
    this.transport.abortAuthenticated(reason);
  }

  async request<T>(
    method: HttpMethod,
    resource: string,
    options: { params?: QueryParams; body?: unknown; signal?: AbortSignal } = {},
  ): Promise<ApiResponse<T>> {
    const data = await this.transport.request<T>({
      method,
      path: resource,
      params: options.params,
      body: options.body,
      signal: options.signal,
      authRequired: false,
    });
    return { success: true, data };
  }

  get<T>(
    resource: string,
    params?: QueryParams,
    options?: { signal?: AbortSignal },
  ): Promise<ApiResponse<T>> {
    return this.request<T>('GET', resource, { params, signal: options?.signal });
  }

  post<T>(
    resource: string,
    body?: unknown,
    params?: QueryParams,
    options?: { signal?: AbortSignal },
  ): Promise<ApiResponse<T>> {
    return this.request<T>('POST', resource, { body, params, signal: options?.signal });
  }

  put<T>(
    resource: string,
    body?: unknown,
    params?: QueryParams,
    options?: { signal?: AbortSignal },
  ): Promise<ApiResponse<T>> {
    return this.request<T>('PUT', resource, { body, params, signal: options?.signal });
  }

  delete<T>(
    resource: string,
    params?: QueryParams,
    options?: { signal?: AbortSignal },
  ): Promise<ApiResponse<T>> {
    return this.request<T>('DELETE', resource, { params, signal: options?.signal });
  }
}

export { ToughLeafApiError, parseApiError };
