import type { ApiErrorBody } from './types.js';

export class ToughLeafApiError extends Error {
  readonly status: number;
  readonly body?: ApiErrorBody;

  constructor(status: number, message: string, body?: ApiErrorBody) {
    super(message);
    this.name = 'ToughLeafApiError';
    this.status = status;
    this.body = body;
  }

  get isUnauthorized(): boolean {
    return this.status === 401;
  }

  get isValidationError(): boolean {
    return this.status === 422;
  }

  get isRateLimited(): boolean {
    return this.status === 429;
  }
}

export async function parseApiError(response: Response): Promise<ToughLeafApiError> {
  let body: ApiErrorBody | undefined;
  try {
    const json = (await response.json()) as { error?: ApiErrorBody };
    body = json.error;
  } catch {
    body = undefined;
  }
  const message = body?.message ?? response.statusText ?? `HTTP ${response.status}`;
  return new ToughLeafApiError(response.status, message, body);
}
