import { parseApiError, ToughLeafApiError } from '../errors.js';
import type { ApiResponse, QueryParams } from '../types.js';
import type { FetchTransportOptions, HttpMethod, HttpTransport, RequestSpec } from './types.js';

interface ActiveAuthRequest {
  controller: AbortController;
}

export class FetchTransport implements HttpTransport {
  private readonly baseUrl: string;
  private readonly getAccessToken?: FetchTransportOptions['getAccessToken'];
  private readonly fetchImpl: typeof fetch;
  private readonly onUnauthorized?: FetchTransportOptions['onUnauthorized'];
  private readonly activeAuthRequests = new Set<ActiveAuthRequest>();

  constructor(options: FetchTransportOptions) {
    const normalized = options.baseUrl.replace(/\/+$/, '');
    this.baseUrl = normalized.endsWith('/api/v1') ? normalized : `${normalized}/api/v1`;
    this.getAccessToken = options.getAccessToken;
    this.fetchImpl = options.fetchImpl ?? globalThis.fetch.bind(globalThis);
    this.onUnauthorized = options.onUnauthorized;
  }

  get apiBaseUrl(): string {
    return this.baseUrl;
  }

  abortAuthenticated(_reason?: string): void {
    for (const active of this.activeAuthRequests) {
      active.controller.abort();
    }
    this.activeAuthRequests.clear();
  }

  async request<T>(spec: RequestSpec): Promise<T> {
    const authRequired = spec.authRequired !== false;
    const controller = new AbortController();
    const linked = this.linkSignal(spec.signal, controller);

    if (authRequired) {
      const active: ActiveAuthRequest = { controller };
      this.activeAuthRequests.add(active);
      try {
        return await this.executeRequest<T>(spec, controller.signal);
      } finally {
        this.activeAuthRequests.delete(active);
      }
    }

    return this.executeRequest<T>(spec, linked);
  }

  private linkSignal(external: AbortSignal | undefined, controller: AbortController): AbortSignal {
    if (!external) {
      return controller.signal;
    }
    if (external.aborted) {
      controller.abort();
    } else {
      external.addEventListener('abort', () => controller.abort(), { once: true });
    }
    return controller.signal;
  }

  private async executeRequest<T>(spec: RequestSpec, signal: AbortSignal): Promise<T> {
    const hasBody = spec.body !== undefined && spec.method !== 'GET' && spec.method !== 'DELETE';
    const url = this.buildUrl(spec.path, spec.params);

    let response: Response;
    try {
      response = await this.fetchImpl(url, {
        method: spec.method,
        headers: await this.headers(hasBody),
        body: hasBody ? JSON.stringify(spec.body) : undefined,
        signal,
      });
    } catch (err) {
      if (signal.aborted) {
        throw err;
      }
      throw err;
    }

    return this.handleResponse<T>(response);
  }

  private buildUrl(resource: string, params?: QueryParams): string {
    const path = resource.startsWith('/') ? resource : `/${resource}`;
    const joined = `${this.baseUrl}${path}`;

    if (/^https?:\/\//i.test(this.baseUrl)) {
      const url = new URL(joined);
      if (params) {
        for (const [key, value] of Object.entries(params)) {
          if (value !== undefined && value !== null && value !== '') {
            url.searchParams.set(key, String(value));
          }
        }
      }
      return url.toString();
    }

    // Relative base (e.g. /api/v1 behind Vite proxy) — browser fetch accepts this
    let urlStr = joined;
    if (params) {
      const search = new URLSearchParams();
      for (const [key, value] of Object.entries(params)) {
        if (value !== undefined && value !== null && value !== '') {
          search.set(key, String(value));
        }
      }
      const qs = search.toString();
      if (qs) {
        urlStr += `${urlStr.includes('?') ? '&' : '?'}${qs}`;
      }
    }
    return urlStr;
  }

  private async headers(hasBody: boolean): Promise<HeadersInit> {
    const headers: Record<string, string> = {
      Accept: 'application/json',
    };
    if (hasBody) {
      headers['Content-Type'] = 'application/json';
    }
    const token = this.getAccessToken ? await this.getAccessToken() : undefined;
    if (token) {
      headers.Authorization = `Bearer ${token}`;
    }
    return headers;
  }

  private async handleResponse<T>(response: Response): Promise<T> {
    if (!response.ok) {
      const err = await parseApiError(response);
      if (err.isUnauthorized && this.onUnauthorized) {
        await this.onUnauthorized();
      }
      throw err;
    }
    const text = await response.text();
    if (!text) {
      return undefined as T;
    }
    const json = JSON.parse(text) as ApiResponse<T>;
    return json.data as T;
  }

  /** Convenience wrappers used by resources */
  get<T>(path: string, params?: QueryParams, options?: Partial<RequestSpec>): Promise<T> {
    return this.request<T>({ method: 'GET', path, params, authRequired: true, ...options });
  }

  post<T>(path: string, body?: unknown, params?: QueryParams, options?: Partial<RequestSpec>): Promise<T> {
    return this.request<T>({ method: 'POST', path, body, params, authRequired: true, ...options });
  }

  put<T>(path: string, body?: unknown, params?: QueryParams, options?: Partial<RequestSpec>): Promise<T> {
    return this.request<T>({ method: 'PUT', path, body, params, authRequired: true, ...options });
  }

  delete<T>(path: string, params?: QueryParams, options?: Partial<RequestSpec>): Promise<T> {
    return this.request<T>({ method: 'DELETE', path, params, authRequired: true, ...options });
  }

  getPublic<T>(path: string, params?: QueryParams, options?: Partial<RequestSpec>): Promise<T> {
    return this.request<T>({ method: 'GET', path, params, authRequired: false, ...options });
  }
}

export { ToughLeafApiError };
export type { HttpMethod };
