import type { CompanyData } from '../types.js';

export interface LaravelPhysicalAddress {
  address: string;
  city: string;
  state: string;
  zip: string;
}

/** PUT /api/v1/company (AccountController) requires a full body — not partial like PATCH. */
export function buildLaravelAccountCompanyPutBody(
  current: CompanyData,
  patch: Partial<CompanyData>,
): Record<string, unknown> {
  const physical = resolvePhysicalAddress(current, patch);

  const body = {
    company_type: pickField(patch, current, 'company_type'),
    company_name: pickField(patch, current, 'company_name'),
    owner_first: pickField(patch, current, 'owner_first'),
    owner_last: pickField(patch, current, 'owner_last'),
    email: pickField(patch, current, 'email'),
    phone: pickField(patch, current, 'phone'),
    website: pickField(patch, current, 'website') ?? '',
    physical_address: physical,
  };

  const missing = (['company_type', 'company_name', 'owner_first', 'owner_last', 'email', 'phone'] as const).filter(
    (key) => body[key] === undefined || body[key] === null || String(body[key]).trim() === '',
  );
  if (missing.length) {
    throw new Error(
      `PUT /company missing required fields after merge with GET /company: ${missing.join(', ')}. ` +
        'Laravel AccountController requires a full company body — ensure the company record is complete (re-seed dev DB).',
    );
  }

  return body;
}

function pickField(
  patch: Partial<CompanyData>,
  current: CompanyData,
  key: keyof CompanyData,
): unknown {
  if (Object.prototype.hasOwnProperty.call(patch, key)) {
    return patch[key];
  }
  const fromCurrent = current[key];
  if (fromCurrent !== undefined && fromCurrent !== null && String(fromCurrent).trim() !== '') {
    return fromCurrent;
  }
  return undefined;
}

function resolvePhysicalAddress(
  current: CompanyData,
  patch: Partial<CompanyData>,
): LaravelPhysicalAddress {
  const fromPatch = patch.physical_address as Partial<LaravelPhysicalAddress> | undefined;
  const fromCurrent = current.physical_address as Partial<LaravelPhysicalAddress> | undefined;
  const fromAddresses = physicalFromAddresses(current.addresses);

  const merged: LaravelPhysicalAddress = {
    address: String(fromPatch?.address ?? fromCurrent?.address ?? fromAddresses?.address ?? ''),
    city: String(fromPatch?.city ?? fromCurrent?.city ?? fromAddresses?.city ?? ''),
    state: String(fromPatch?.state ?? fromCurrent?.state ?? fromAddresses?.state ?? ''),
    zip: String(fromPatch?.zip ?? fromCurrent?.zip ?? fromAddresses?.zip ?? ''),
  };

  if (!merged.address || !merged.city || !merged.state || !merged.zip) {
    throw new Error(
      'PUT /company requires physical_address (address, city, state, zip). Call getCompany() first or include physical_address in the patch.',
    );
  }

  return merged;
}

function physicalFromAddresses(
  addresses: unknown,
): Partial<LaravelPhysicalAddress> | undefined {
  if (!Array.isArray(addresses)) {
    return undefined;
  }

  const physical =
    addresses.find((row) => {
      if (!row || typeof row !== 'object') return false;
      const type = (row as Record<string, unknown>).type;
      return type === 1 || type === '1';
    }) ?? addresses[0];

  if (!physical || typeof physical !== 'object') {
    return undefined;
  }

  const row = physical as Record<string, unknown>;
  return {
    address: String(row.address ?? row.street ?? ''),
    city: String(row.city ?? ''),
    state: String(row.state ?? row.state_abbr ?? ''),
    zip: String(row.zip ?? ''),
  };
}
