import type { HttpClient } from '../http.js';
import type { LoginResponse } from '../types.js';

export interface UserLoginInfo {
  email: string;
  password: string;
}

export class AuthResource {
  constructor(private readonly http: HttpClient) {}

  async login(info: UserLoginInfo): Promise<LoginResponse> {
    const resp = await this.http.post<LoginResponse>('/auth/login', info);
    return resp.data;
  }

  async refresh(): Promise<LoginResponse> {
    const resp = await this.http.post<LoginResponse>('/auth/refresh');
    return resp.data;
  }
}
